import { Component } from '@angular/core';
import { Item } from 'src/app/models/item';
import { DataService } from 'src/app/services/data.service';

@Component({
  selector: 'app-add-items',
  templateUrl: './add-items.component.html',
  styleUrls: ['./add-items.component.css']
})
export class AddItemsComponent {
  item: Item = new Item();
  constructor(
    private svc:DataService
  ) { }

  onSubmitForm() {
    this.svc.postItem(this.item).subscribe(x => console.log("item added")
    )
  }

}
<div class="row">
  <div class="col">
    <h2 class="display-5">Add new items</h2>
  </div>
  <form #f="ngForm" (ngSubmit)="onSubmitForm()">
    <div class="row">
      <label class="form-label fw-bold col-2">Item Name</label>
      <div class="col-8">
        <input
          class="form-control form-control-sm"
          name="ItemName"
          [(ngModel)]="item.itemName"
          #ItemName="ngModel"
        />
      </div>
      <div class="col-2">
        <span class="text-danger"></span>
      </div>
    </div>
  </form>
</div>
